-- Sprint 04 SaaS plans, modules, subscriptions and monthly usage.
create table if not exists valorapesquisa.plans(id uuid primary key default gen_random_uuid(),code text not null unique,name text not null,description text,monthly_price numeric(12,2) not null default 0,annual_price numeric(12,2) not null default 0,status text not null default 'active',display_order int not null default 0,created_at timestamptz not null default now(),updated_at timestamptz,is_deleted boolean not null default false);
create table if not exists valorapesquisa.plan_limits(id uuid primary key default gen_random_uuid(),plan_id uuid not null references valorapesquisa.plans(id) on delete cascade,active_surveys int not null,responses_per_month int not null,users int not null,managers int not null,forms int not null,public_links int not null,email_invites_per_month int not null,storage_mb int not null,created_at timestamptz not null default now(),updated_at timestamptz,unique(plan_id));
create table if not exists valorapesquisa.plan_capabilities(id uuid primary key default gen_random_uuid(),plan_id uuid not null references valorapesquisa.plans(id) on delete cascade,capability_code text not null,enabled boolean not null default false,unique(plan_id,capability_code));
create table if not exists valorapesquisa.modules(id uuid primary key default gen_random_uuid(),code text not null unique,name text not null,description text,category text not null default 'core',status text not null default 'active',display_order int not null default 0,minimum_plan_code text,created_at timestamptz not null default now(),updated_at timestamptz,is_deleted boolean not null default false);
create table if not exists valorapesquisa.organization_modules(id uuid primary key default gen_random_uuid(),organization_id uuid not null references valorapesquisa.organizations(id) on delete cascade,module_id uuid not null references valorapesquisa.modules(id) on delete cascade,enabled boolean not null default true,source text not null default 'plan',created_at timestamptz not null default now(),updated_at timestamptz,unique(organization_id,module_id));
create table if not exists valorapesquisa.subscriptions(id uuid primary key default gen_random_uuid(),organization_id uuid not null references valorapesquisa.organizations(id) on delete cascade,plan_id uuid not null references valorapesquisa.plans(id),status text not null default 'active',billing_status text not null default 'ok',starts_at timestamptz not null default now(),expires_at timestamptz,trial_ends_at timestamptz,cancelled_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz);
create table if not exists valorapesquisa.usage_monthly(id uuid primary key default gen_random_uuid(),organization_id uuid not null references valorapesquisa.organizations(id) on delete cascade,month date not null,active_surveys_count int not null default 0,responses_count int not null default 0,users_count int not null default 0,managers_count int not null default 0,forms_count int not null default 0,public_links_count int not null default 0,email_invites_count int not null default 0,storage_mb_used int not null default 0,updated_at timestamptz not null default now(),unique(organization_id,month));
create index if not exists ix_plans_code on valorapesquisa.plans(code); create index if not exists ix_plans_status on valorapesquisa.plans(status); create index if not exists ix_plan_limits_plan_id on valorapesquisa.plan_limits(plan_id); create index if not exists ix_plan_capabilities_plan_capability on valorapesquisa.plan_capabilities(plan_id,capability_code); create index if not exists ix_modules_code on valorapesquisa.modules(code); create index if not exists ix_modules_status on valorapesquisa.modules(status); create index if not exists ix_organization_modules_organization_id on valorapesquisa.organization_modules(organization_id); create index if not exists ix_organization_modules_module_id on valorapesquisa.organization_modules(module_id); create index if not exists ix_subscriptions_organization_id on valorapesquisa.subscriptions(organization_id); create index if not exists ix_subscriptions_plan_id on valorapesquisa.subscriptions(plan_id); create index if not exists ix_subscriptions_status on valorapesquisa.subscriptions(status); create index if not exists ix_usage_monthly_organization_month on valorapesquisa.usage_monthly(organization_id,month);
insert into valorapesquisa.plans(code,name,description,monthly_price,annual_price,status,display_order) values ('free','Free','Entrada gratuita com limites reduzidos.',0,0,'active',1),('essential','Essential','Plano essencial para operação inicial.',99,990,'active',2),('growth','Growth','Plano de crescimento com relatórios e certificados.',299,2990,'active',3),('enterprise','Enterprise','Plano corporativo com limites ampliados.',0,0,'active',4),('internal','Internal','Uso interno Valora.',0,0,'active',0) on conflict(code) do update set name=excluded.name,description=excluded.description,status=excluded.status,display_order=excluded.display_order;
insert into valorapesquisa.plan_limits(plan_id,active_surveys,responses_per_month,users,managers,forms,public_links,email_invites_per_month,storage_mb) select id,1,30,1,1,1,1,0,100 from valorapesquisa.plans where code='free' on conflict(plan_id) do update set active_surveys=1,responses_per_month=30,users=1,managers=1,forms=1,public_links=1,email_invites_per_month=0,storage_mb=100;
insert into valorapesquisa.plan_limits(plan_id,active_surveys,responses_per_month,users,managers,forms,public_links,email_invites_per_month,storage_mb) select id,3,150,3,3,3,5,150,500 from valorapesquisa.plans where code='essential' on conflict(plan_id) do update set active_surveys=3,responses_per_month=150,users=3,managers=3,forms=3,public_links=5,email_invites_per_month=150,storage_mb=500;
insert into valorapesquisa.plan_limits(plan_id,active_surveys,responses_per_month,users,managers,forms,public_links,email_invites_per_month,storage_mb) select id,12,1000,10,10,20,50,1000,2048 from valorapesquisa.plans where code='growth' on conflict(plan_id) do update set active_surveys=12,responses_per_month=1000,users=10,managers=10,forms=20,public_links=50,email_invites_per_month=1000,storage_mb=2048;
insert into valorapesquisa.plan_limits(plan_id,active_surveys,responses_per_month,users,managers,forms,public_links,email_invites_per_month,storage_mb) select id,-1,-1,-1,-1,-1,-1,-1,-1 from valorapesquisa.plans where code in ('enterprise','internal') on conflict(plan_id) do update set active_surveys=-1,responses_per_month=-1,users=-1,managers=-1,forms=-1,public_links=-1,email_invites_per_month=-1,storage_mb=-1;
insert into valorapesquisa.modules(code,name,description,category,status,display_order,minimum_plan_code) values ('clientes','Clientes','Gestão de organizações clientes.','admin','active',1,'enterprise'),('planos','Planos','Gestão de planos comerciais.','admin','active',2,'enterprise'),('modulos','Módulos','Gestão de módulos.','admin','active',3,'enterprise'),('usuarios','Usuários','Gestão de usuários.','core','active',4,'free'),('formularios','Formulários','Criação de formulários.','core','active',5,'free'),('pesquisas','Pesquisas','Criação e publicação de pesquisas.','core','active',6,'free'),('links_publicos','Links públicos','Links públicos de resposta.','core','active',7,'free'),('respostas','Respostas','Recebimento e consulta de respostas.','core','active',8,'free'),('relatorios','Relatórios','Indicadores e relatórios.','analytics','active',9,'essential'),('certificados','Certificados','Certificados ricos futuros.','premium','active',10,'growth'),('convites_email','Convites por e-mail','Convites por e-mail.','communication','active',11,'essential'),('auditoria','Auditoria','Trilha de auditoria.','security','active',12,'enterprise'),('lgpd','LGPD','Solicitações LGPD futuras.','security','active',13,'enterprise'),('suporte','Suporte','Suporte comercial.','support','active',14,'enterprise'),('white_label','White label','Marca do cliente.','premium','active',15,'growth'),('benchmark','Benchmark','Comparativos agregados.','analytics','active',16,'growth'),('exportacoes','Exportações','Exportação Excel/PDF.','analytics','active',17,'essential'),('integracoes','Integrações','API e integrações futuras.','platform','active',18,'enterprise'),('dashboard','Dashboard','Painéis operacionais.','core','active',19,'free'),('configuracoes','Configurações','Configurações da organização.','core','active',20,'free') on conflict(code) do update set name=excluded.name,description=excluded.description,category=excluded.category,status=excluded.status,display_order=excluded.display_order,minimum_plan_code=excluded.minimum_plan_code;
insert into valorapesquisa.subscriptions(id,organization_id,plan_id,status,billing_status,starts_at,created_at) select gen_random_uuid(),o.id,p.id,'active','ok',now(),now() from valorapesquisa.organizations o join valorapesquisa.plans p on p.code=case when o.plan_code='internal' then 'enterprise' else o.plan_code end where not exists(select 1 from valorapesquisa.subscriptions s where s.organization_id=o.id);
insert into valorapesquisa.organization_modules(id,organization_id,module_id,enabled,source,created_at) select gen_random_uuid(),o.id,m.id,true,'plan',now() from valorapesquisa.organizations o cross join valorapesquisa.modules m where not exists(select 1 from valorapesquisa.organization_modules om where om.organization_id=o.id and om.module_id=m.id) and (o.plan_code in ('internal','enterprise') or m.minimum_plan_code in ('free','essential','growth'));
